custom_css:
#chat {
    padding: 0 !important;
    overflow-y: scroll;
}

body.bubblechat .mes {
    padding: 0px 0px 16px 0px;
    display: flex;
    flex-direction: column;
}

body .mes[is_user="false"] {
    margin-top: 8px;
    margin-bottom: 16px;
}

.mesAvatarWrapper {
    display: flex;
    flex-direction: row;
    align-items: center;
    gap: 8px;
    padding: 16px 16px 0px 16px;
    overflow: hidden;
    width: 100%;
    padding-bottom: 3px;
}

body.bubblechat .mes[is_user="true"] .mesAvatarWrapper {
    flex-direction: row-reverse;
}

body.bubblechat .mes[is_user="true"] .mesAvatarWrapper .avatar {
    flex: 0 0 auto;
}

body.bubblechat .mes[is_user="true"] .mesAvatarWrapper > .mesIDDisplay,
body.bubblechat .mes[is_user="true"] .mesAvatarWrapper > .mes_timer,
body.bubblechat .mes[is_user="true"] .mesAvatarWrapper > .tokenCounterDisplay {
    margin-right: auto;
}

body.bubblechat .mes[is_user="true"] .mesAvatarWrapper > .mes_timer,
body.bubblechat .mes[is_user="true"] .mesAvatarWrapper > .tokenCounterDisplay {
    margin-right: 0;
}

.mes .avatar img {
    padding: 0px;
}

body.square-avatars .avatar,
body.square-avatars .avatar img {
    border-radius: 0 !important;
}

body.big-avatars .avatar {
    align-items: self-start !important;
}

.mes_block .ch_name {
    padding: 16px;
    margin-bottom: 8px;
}

.mes_block .ch_name .flex-container {
    min-width: 0;
    flex: 1 1 auto;
}

body .mes[is_user="true"] .mes_block .ch_name,
body .mes[is_user="true"] .mes_block .ch_name .flex-container {
    flex-direction: row-reverse;
}

.mes_text {
    padding: 0px 4px !important;
}

.mes_text p {
    margin-bottom: 12px;
}

.mes_text blockquote,
.mes_reasoning blockquote {
    padding: 8px;
    margin-bottom: 8px;
}

code {
    padding: 4px 3px;
}

.mes_text pre {
    padding: 12px 14px;
    overflow-x: auto;
    position: relative;
}

.mes_text table {
    width: 100%;
    border-collapse: collapse;
    margin: 8px 0;
    overflow: hidden;
}

.mes_text th,
.mes_text td {
    padding: 10px 14px;
}

.mes_text q {
    margin: 0px 6px 0px 3px;
    padding: 5px 4px;
}

.mes_reasoning_details .mes_reasoning_summary,
.mes_reasoning,
.reasoning_edit_textarea {
    margin-left: 16px !important;
    margin-right: 16px !important;
}

.reasoning_edit_textarea {
    width: 100% !important;
}

.mes_reasoning_header_block {
    margin-top: 8px;
    margin-bottom: 16px;
}

.mes_reasoning_header {
    justify-content: center;
    margin: 0px;
}

.swipes-counter {
    margin: 0px;
    min-width: max-content;
}

.flex-container.swipeRightBlock {
    display: flex;
    flex-direction: row-reverse;
    padding-bottom: 20px;
    margin-right: 16px;
}

.last_mes .mesAvatarWrapper {
    padding-bottom: 5px !important;
}

.mes_block {
    padding-left: 0px !important;
}
